from flask import Flask, request, redirect, url_encode
from flask_oauthlib.client import OAuth

app = Flask(__name__)
config = {
    'GOOGLE': {
        'client_id': 'YOUR_CLIENT_ID',
        'client_secret': 'YOUR_CLIENT_SECRET',
        'base_url': 'https://accounts.google.com/o/oauth2/',
        'authorize_url': 'https://accounts.google.com/o/oauth2/auth',
        'access_token_url': 'https://oauth2.googleapis.com/token'
    },
    'DOMAIN': 'your-domain.com'  # Replace with your domain for subdomain support
}

oauth = OAuth(app)

google = oauth.remote_app(
    'google',
    consumer_key=config['GOOGLE']['client_id'],
    consumer_secret=config['GOOGLE']['client_secret'],
    request_token_params={
        'scope': ['profile', 'email']
    },
    base_url=config['GOOGLE']['base_url'],
    authorize_url=config['GOOGLE']['authorize_url'],
    access_token_method='post'
)

@app.route('/')
def index():
    callback = url_encode({'callback': request.host_url + '/callback'})
    return f"Please go to the following URL to authorize with Google:\n{google.authorize_redirect(callback)}"

@app.route('/callback')
def callback():
    if not google.authorized:
        return redirect(google.authorize_redirect())
    access_token = google.authorized_access_token()
    resp = google.get('userinfo', token=access_token)
    return f"Access token: {resp['access_token']}\nUser info:\n{resp}"

def is_valid_domain(uri):
    domain = config['DOMAIN']
    if not uri or '?' in uri or '#' in uri:
        return False
    uri_components = uri.split('/')
    if len(uri_components) < 2:
        return False
    host = uri_components[1]
    if not host or host == '@':
        return False
    return domain in host or host.endswith(f'.{domain}')

@app.route('/authorize')
def authorize():
    redirect_uri = request.args.get('redirect_uri', None)
    if not redirect_uri:
        return "Missing required parameter 'redirect_uri'", 400
    if not is_valid_domain(redirect_uri):
        return f"Invalid domain for redirect URI '{redirect_uri}'", 403
    callback = url_encode({'callback': request.host_url + '/callback'})
    return f"Please go to the following URL to authorize with Google:\n{google.authorize_redirect(redirect_uri, callback)}"